#include<bits/stdc++.h>
using namespace std;
const __int128 mod=353442899;
__int128 getsum(__int128 l,__int128 r)
{
    return (l+r)*176721450%mod*(r-l+1)%mod;
}
__int128 n;
__int128 tot;
struct node
{
    __int128 l,r,val;
}b[101];
__int128 query(__int128 x)
{
    if(x==0)
    {
        return 0;
    }
    __int128 sum=-1;
    for(__int128 i=1;i<=tot;i++)
    {
        __int128 l=(i==1?1ll:b[i-1].r+1);
        __int128 r=min(b[i].l-1,x);
        __int128 val=(i==1?2ll:b[i-1].val+1)%mod;
        sum+=getsum(val,val+r-l);
        sum%=mod;
        if(r==x)
        {
            break;
        }
        l=b[i].l;
        r=min(b[i].r,x);
        val=b[i].val;
        sum+=val*(r-l+1+mod)%mod;
        sum%=mod;
        if(r==x)
        {
            break;
        }
    }
    return sum;
}
int main()
{
    long long t;
    scanf("%lld",&t);
    for(__int128 l=6,r=7;l<=1e18;l<<=1,r=r<<1|1)
    {
        b[tot+1]={l,r,((1ll<<(tot+2))+tot+3)%mod};
        tot++;
    }
    while(t--)
    {
        __int128 l,r;
        long long a,b;
        scanf("%lld%lld",&a,&b);
        l=a;
        r=b;
        printf("%lld\n",(long long)(((query(r)-query(l-1))%mod+mod)%mod));
    }
    return 0;
}
